Người dùng gõ nhanh "rea" → "react". Request "rea" có thể về sau "react" và ghi đè kết quả đúng. Giải pháp:

```javascript
import { useState, useEffect } from 'react';
import { AbortController } from 'abort-controller';

let controller;
const DEBOUNCE_TIME = 300; // thời gian chờ trước khi gửi request mới

async function search(query) {
  controller?.abort(); // hủy request cũ
  controller = new AbortController();
  const res = await fetch(`/api?q=${query}`, {
    signal: controller.signal
  });
  return res.json();
}

function useDebounce(value, delay) {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const timeoutId = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => {
      clearTimeout(timeoutId);
    };
  }, [value, delay]);

  return debouncedValue;
}

function App() {
  const [query, setQuery] = useState('');
  const [result, setResult] = useState(null);
  const debouncedQuery = useDebounce(query, DEBOUNCE_TIME);

  useEffect(() => {
    if (debouncedQuery) {
      search(debouncedQuery).then((data) => {
        if (debouncedQuery === query) { // kiểm tra request này có còn là mới nhất không
          setResult(data);
        }
      });
    }
  }, [debouncedQuery, query]);

  const handleInputChange = (e) => {
    setQuery(e.target.value);
  };

  return (
    <div>
      <input type="text" value={query} onChange={handleInputChange} />
      <p>Kết quả: {result}</p>
    </div>
  );
}
```

Trong giải pháp này, chúng ta sử dụng `AbortController` để hủy request cũ khi người dùng gõ nhanh. Chúng ta cũng sử dụng `useDebounce` hook để giảm số request và kiểm tra "request này có còn là mới nhất không" trước khi setState.

